module register_8bit_enable(clk, enable, d, q);  

    input  clk;  
    input  enable;  
    input  [7:0] d;  
    output  [7:0] q;  
    reg   [7:0]  q; 
    initial q = 0;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
          begin
            if (enable)
                q <= d;
          end  

endmodule
